// Absolute final controller: loaded last. Owns top nav, Schedule, Admin menu/pages.
(function(){
  function esc(v){return String(v==null?'':v).replace(/[&<>"']/g,function(c){return {'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]})}
  function monday(d){d=new Date(d||new Date());var n=(d.getDay()+6)%7;d.setHours(12,0,0,0);d.setDate(d.getDate()-n);return d}
  function add(d,n){d=new Date(d);d.setDate(d.getDate()+n);return d}
  function iso(d){return d.toISOString().slice(0,10)}
  function label(d,opts){return new Date(d+'T12:00:00').toLocaleDateString('en-GB',opts)}
  function days(){var base=window.__rbWeekStart?new Date(window.__rbWeekStart+'T12:00:00'):monday(new Date());base=monday(base);window.__rbWeekStart=iso(base);return [0,1,2,3,4,5,6].map(function(n){return iso(add(base,n))})}
  function uname(id){if(!id||id==='unassigned')return 'Unassigned';var u=(state.users||[]).find(function(x){return x.id===id});return u?(u.nickname||u.name||u.firstName||'User'):'Unassigned'}
  function isPub(s,first){return !!s.publishedAt || !!(state.publishedWeeks&&state.publishedWeeks[first]&&(state.publishedWeeks[first].shiftIds||[]).includes(s.id))}
  function isOnShift(s){var l=(state.logs||{})[s.id];return !!(l&&l.in&&!l.out)}
  function shiftCard(s,first){var live=isOnShift(s),cls=s.userId==='unassigned'?'unassigned':live?'onShift':isPub(s,first)?'published':'planned';var notes=s.notes||'';return '<button type="button" class="scheduleShiftBlock '+cls+'" onclick="openShiftModal(\''+s.id+'\')"><span class="shiftLine shiftUserLine">'+esc(uname(s.userId))+'</span><span class="shiftLine shiftTimeLine">'+esc(s.start)+'-'+esc(s.end)+'</span><span class="shiftLine shiftNotesLine">'+(notes?esc(notes):'&nbsp;')+'</span>'+(live?'<span class="shiftLine shiftStatusLine">On Shift</span>':'')+'</button>'}
  function topShell(inner){var u=me();var set=state.permissionSets[u.permissionSetId]||{name:'Staff'};var nav=['<button class="tab '+(state.view==='home'?'active':'')+'" onclick="setView(\'home\')">Home</button>','<button class="tab '+(state.view==='rota'?'active':'')+'" onclick="setView(\'rota\')">Schedule</button>'];if(can('viewPeople')||can('manageUsers'))nav.push('<button class="tab '+(state.view==='people'?'active':'')+'" onclick="setView(\'people\')">People</button>');if(isAdmin())nav.push('<button class="tab '+(state.view==='admin'?'active':'')+'" onclick="setView(\'admin\')">Admin</button>');document.getElementById('app').innerHTML='<header class="topbar"><div><h1>Rota App</h1><p>'+esc(u.name)+' · '+esc(set.name||'Staff')+'</p></div><div class="topActions"><select id="currentUserSelect">'+state.users.map(function(x){return '<option value="'+x.id+'" '+(x.id===state.currentUserId?'selected':'')+'>'+esc(x.nickname||x.name)+' ('+esc((state.permissionSets[x.permissionSetId]||{}).name||'Staff')+')</option>'}).join('')+'</select></div></header><nav class="tabs">'+nav.join('')+'</nav><main>'+inner+'</main>';document.getElementById('currentUserSelect').onchange=function(e){state.currentUserId=e.target.value;save();render()}}
  function scheduleTools(){if(typeof can==='function'&&!can('manageRota'))return '';return '<div class="scheduleAdminTools"><h2>Rota planning</h2><div class="planningActions scheduleActions"><button onclick="copyCurrentWeek()">Copy current week</button><button class="secondary" onclick="pasteCopiedWeek()">Paste copied week here</button><button class="secondary" onclick="saveCurrentWeekAsTemplate()">Save week as template</button><button onclick="openSaveRotaModal()">Save rota</button></div></div>'}
  function renderRotaFinal(){var ds=days(),first=ds[0],last=ds[6];var range=label(first,{day:'numeric',month:'short',year:'numeric'})+' - '+label(last,{day:'numeric',month:'short',year:'numeric'});var html='<div class="toolbar scheduleToolbarFinal"><button class="secondary" onclick="window.__rbWeekStart=iso(add(new Date(window.__rbWeekStart+\'T12:00:00\'),-7));renderRota()">‹</button><strong>'+range+'</strong><button class="secondary" onclick="window.__rbWeekStart=iso(add(new Date(window.__rbWeekStart+\'T12:00:00\'),7));renderRota()">›</button></div><div id="rotaGrid" class="bandedRota"><div class="bandDayHeader">'+ds.map(function(d){return '<div class="bandDayHead"><strong>'+label(d,{weekday:'short'})+'</strong><span>'+label(d,{day:'numeric',month:'short'})+'</span></div>'}).join('')+'</div>'+(state.sections||[]).map(function(sec){return '<section class="rotaSectionBand"><div class="sectionBandTitle">'+esc(sec)+'</div><div class="bandWeekGrid">'+ds.map(function(d){var shifts=(state.shifts||[]).filter(function(s){return s.section===sec&&s.date===d}).sort(function(a,b){return String(a.start).localeCompare(String(b.start))});return '<div class="bandDayCell compactDayCell">'+(shifts.length?shifts.map(function(s){return shiftCard(s,first)}).join(''):'<span class="muted emptyCell">—</span>')+((typeof can!=='function'||can('manageRota'))?'<button class="cellAddShift" onclick="openShiftModal(\'\',\''+d+'\',\''+esc(sec)+'\')">+</button>':'')+'</div>'}).join('')+'</div></section>'}).join('')+'</div>'+scheduleTools();topShell(html);window.scrollTo(0,0)}
  function adminMenu(){return '<section class="panel adminHomePanel"><h2>Admin</h2><div class="adminMenuStack"><button class="adminMenuButton" onclick="openAdminSection(\'shift\')"><span>Add / Edit Shifts</span><small>Create and amend shifts</small></button><button class="adminMenuButton" onclick="openAdminSection(\'sections\')"><span>Sections</span><small>Manage rota areas</small></button><button class="adminMenuButton" onclick="openAdminSection(\'users\')"><span>Users</span><small>Manage profiles and costs</small></button><button class="adminMenuButton" onclick="openAdminSection(\'permissions\')"><span>Permission Sets</span><small>Control access</small></button><button class="adminMenuButton" onclick="openAdminSection(\'timesheets\')"><span>Timesheets</span><small>All shift records</small></button></div></section>'}
  function shiftPage(){return '<h2>Add / edit shift</h2><form class="formGrid" onsubmit="saveShift(event)"><label>Staff member<select id="shiftUser"><option value="unassigned">Unassigned</option>'+state.users.map(function(u){return '<option value="'+u.id+'">'+esc(u.name)+'</option>'}).join('')+'</select></label><label>Section<select id="shiftSection">'+state.sections.map(function(s){return '<option>'+esc(s)+'</option>'}).join('')+'</select></label><label>Date<input id="shiftDate" type="date" value="'+iso(new Date())+'"></label><label>Start<input id="shiftStart" type="time" value="09:00"></label><label>End<input id="shiftEnd" type="time" value="17:00"></label><label class="full">Notes<textarea id="shiftNotes"></textarea></label><button>Save shift</button></form>'}
  function sectionsPage(){return '<h2>Sections</h2><form class="rowForm" onsubmit="addSection(event)"><input id="newSectionName" placeholder="Kitchen, FOH, Office..."><button>Add section</button></form><div class="sectionList">'+state.sections.map(function(s){return '<div class="sectionRow"><span>'+esc(s)+'</span><button class="sectionDeleteBtn" onclick="removeSection(\''+esc(s)+'\')">🗑</button></div>'}).join('')+'</div>'}
  function usersPage(){return '<h2>Users</h2><div class="tableWrap"><table><tr><th>Name</th><th>Role</th><th></th></tr>'+state.users.map(function(u){return '<tr><td>'+esc(u.name)+'</td><td>'+esc((state.permissionSets[u.permissionSetId]||{}).name||'Staff')+'</td><td><button onclick="openProfile(\''+u.id+'\')">Open</button></td></tr>'}).join('')+'</table></div>'}
  function renderAdminFinal(){if(!state.adminPanel||state.adminPanel==='menu'){topShell(adminMenu());return}var content=state.adminPanel==='sections'?sectionsPage():state.adminPanel==='users'?usersPage():state.adminPanel==='permissions'?(typeof renderPermissionSets==='function'?renderPermissionSets():'<p>Permission editor unavailable.</p>'):state.adminPanel==='timesheets'?'<div id="adminInner"></div>':shiftPage();topShell('<section class="panel adminHomePanel"><button class="adminBackButton" onclick="backToAdminMenu()">‹ Back to Admin</button><div class="adminSectionContent">'+content+'</div></section>');if(state.adminPanel==='timesheets'&&typeof renderAdminTimesheetsFinal==='function')renderAdminTimesheetsFinal();window.scrollTo(0,0)}
  window.openAdminSection=function(p){state.adminPanel=p;save();renderAdmin()};window.backToAdminMenu=function(){state.adminPanel='menu';save();renderAdmin()};
  window.renderRota=renderRotaFinal;window.renderAdmin=renderAdminFinal;window.shell=topShell;window.setView=function(v){state.view=v;if(v==='admin')state.adminPanel='menu';save();render()};window.render=function(){if(state.view==='home'||state.view==='clock')renderClock();else if(state.view==='people')renderPeople();else if(state.view==='profile')renderProfile();else if(state.view==='profileEdit')renderProfileEdit();else if(state.view==='admin')renderAdminFinal();else renderRotaFinal()};
  try{renderRota=window.renderRota;renderAdmin=window.renderAdmin;shell=window.shell;setView=window.setView;render=window.render}catch(e){}
  if(!window.__rbWeekStart)window.__rbWeekStart=iso(monday(new Date()));
  render();
})();
